import React, { useState, useEffect } from "react";

function TripForm({ onNewTrip }) {
  const [routes, setRoutes] = useState([]);
  const [trains, setTrains] = useState([]);
  const [routeId, setRouteId] = useState("");
  const [trainId, setTrainId] = useState("");
  const [departureTime, setDepartureTime] = useState("");
  const [arrivalTime, setArrivalTime] = useState("");

  useEffect(() => {
    fetch("http://localhost:5050/routes").then(r=>r.json()).then(setRoutes);
    fetch("http://localhost:5050/trains").then(r=>r.json()).then(setTrains);
  }, []);

  const handleSubmit = async e => {
    e.preventDefault();
    const res = await fetch("http://localhost:5050/trips", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ route_id: parseInt(routeId), train_id: parseInt(trainId), departure_time: departureTime, arrival_time: arrivalTime })
    });
    const data = await res.json();
    if (res.ok) {
      onNewTrip(data);
      setRouteId(""); setTrainId(""); setDepartureTime(""); setArrivalTime("");
    } else alert(data.error);
  };

  return (
    <form onSubmit={handleSubmit}>
      <select value={routeId} onChange={e => setRouteId(e.target.value)}>
        <option value="">Выберите маршрут</option>
        {routes.map(r => <option key={r.id} value={r.id}>{r.departure} → {r.arrival}</option>)}
      </select>
      <select value={trainId} onChange={e => setTrainId(e.target.value)}>
        <option value="">Выберите поезд</option>
        {trains.map(t => <option key={t.id} value={t.id}>{t.number}</option>)}
      </select>
      <input type="time" value={departureTime} onChange={e=>setDepartureTime(e.target.value)} />
      <input type="time" value={arrivalTime} onChange={e=>setArrivalTime(e.target.value)} />
      <button type="submit">Добавить рейс</button>
    </form>
  );
}

export default TripForm;
